class Solution {
    public int maximumCostSubstring(String s, String chars, int[] vals) {
        int n = s.length();
        int[] charMap = new int[26];
        for (int i = 0; i < chars.length(); i++) {
            charMap[chars.charAt(i) - 'a'] = vals[i];
        }
        int maxCost = 0;
        int currentCost = 0;
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            int value;
            if (charMap[c - 'a'] == 0) {
                value = c - 'a' + 1;
            } else {
                value = charMap[c - 'a'];
            }
            currentCost = Math.max(0, currentCost + value);
            maxCost = Math.max(maxCost, currentCost);
        }
        return maxCost;
    }
}
